// httpMethods is the stable-order list of standard HTTP methods checked
// when building the Allow header.
var httpMethods = []string{
	http.MethodConnect,
	http.MethodDelete,
	http.MethodGet,
	http.MethodHead,
	http.MethodOptions,
	http.MethodPatch,
	http.MethodPost,
	http.MethodPut,
	http.MethodTrace,
}

// SetAllowHeader adds the Allow header for 405 responses based on
// registered methods for the requested path.
func SetAllowHeader(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		rctx := chi.RouteContext(r.Context())
		if rctx != nil && rctx.Routes != nil {
			routePath := rctx.RoutePath
			if routePath == "" {
				if r.URL.RawPath != "" {
					routePath = r.URL.RawPath
				} else {
					routePath = r.URL.Path
				}
			}

			if !rctx.Routes.Match(chi.NewRouteContext(), r.Method, routePath) {
				var allowed []string
				for _, method := range httpMethods {
					if method == r.Method {
						continue
					}
					if rctx.Routes.Match(chi.NewRouteContext(), method, routePath) {
						allowed = append(allowed, method)
					}
				}
				if len(allowed) > 0 {
					w.Header().Set("Allow", strings.Join(allowed, ", "))
				}
			}
		}

		next.ServeHTTP(w, r)
	})
}
"}

